import { useState, useCallback, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import ShpeHatAnimation from './ShpeHatAnimation';


const textVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { staggerChildren: 0.2, delayChildren: 0.1 },
  },
};

const lineVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.7, ease: 'easeOut' } },
};

export default function Home() {
  const [stage, setStage] = useState('video'); // 'video' | 'hat'
  const [fadeOut, setFadeOut] = useState(false);
  const [hatDone, setHatDone] = useState(false);
  const videoRef = useRef(null);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.playbackRate = 1.5;
    }
  }, []);

  const handleVideoEnd = useCallback(() => {
    setFadeOut(true);
    setTimeout(() => {
      setFadeOut(false);
      setStage('hat');
    }, 600);
  }, []);

  const handleHatComplete = useCallback(() => {
    setHatDone(true);
  }, []);

  return (
    <main className="font-sans">
      {stage === 'video' && (
        <div
          style={{
            transition: 'opacity 0.6s ease',
            opacity: fadeOut ? 0 : 1,
            width: '100%',
            height: '100vh',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            overflow: 'hidden',
          }}
        >
          <video
            ref={videoRef}
            src={require('../assets/shpe_animated_video.mp4')}
            autoPlay
            muted
            playsInline
            onEnded={handleVideoEnd}
            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
          />
        </div>
      )}

      {stage === 'hat' && (
        <div
          style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            minHeight: '100vh',
            gap: 0,
          }}
        >
          <AnimatePresence>
            {hatDone && (
              <motion.div
                variants={textVariants}
                initial="hidden"
                animate="visible"
                style={{ textAlign: 'center' }}
              >
                <motion.p
                  variants={lineVariants}
                  style={{
                    letterSpacing: '0.2em',
                    fontSize: 'clamp(1.5rem, 4vw, 3rem)',
                    fontWeight: 700,
                    textTransform: 'uppercase',
                    background: 'linear-gradient(135deg, #C8102E 0%, #003087 100%)',
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent',
                    backgroundClip: 'text',
                  }}
                >
                  Bienvenido a
                </motion.p>
              </motion.div>
            )}
          </AnimatePresence>

          <div style={{ marginTop: '-60px' }}>
            <ShpeHatAnimation onComplete={handleHatComplete} speed={1.4} />
          </div>
        </div>
      )}
    </main>
  );
}
